import {
  ChangeDetectorRef,
  Component,
  ElementRef,
  OnInit,
  ViewChild,
} from "@angular/core";
import {
  FormBuilder,
  FormGroup,
  Validators
} from "@angular/forms";
import { IonCheckbox, IonInput } from "@ionic/angular";
import { AlertService } from "src/app/core/services/alert.service";
import { InputMaskingService } from "src/app/core/services/input-masking.service";
import { pagingService } from "src/app/core/services/paging.service";
import { ReferencesService } from "src/app/core/services/references.service";
import { VendorService } from "src/app/core/services/vendor.service";
import { StaticRef } from "src/app/views/Models/References/StaticRef";
import { Category } from "src/app/views/Models/Vendor/category";
import {
  AssignItemsRequest,
  DeleteBranchItem,
  EditBranchItem,
  VendorBranchInfo,
  VendorBranchItem,
  VendorContract,
  VendorInfo,
} from "src/app/views/Models/Vendor/consumer";
import { ItemInfo } from "src/app/views/Models/Vendor/item";

@Component({
  selector: "app-assign-branch-items",
  templateUrl: "./assign-branch-items.page.html",
  styleUrls: ["./assign-branch-items.page.scss"],
})
export class AssignBranchItemsPage implements OnInit {
  @ViewChild("ionCheckBoxBranches") ionCheckBoxBranches: IonCheckbox;
  @ViewChild("ionCheckBoxItems") ionCheckBoxItems: IonCheckbox;
  @ViewChild("categoryContainer") categoryContainer!: ElementRef;
  @ViewChild("searchBranchItemInput") searchBranchItemInput: IonInput;

  //#region Flags
  showLoader: boolean = false;
  showVendors: boolean = false;
  showItems: boolean = false;
  showCategories: boolean = false;
  showBranchItems: boolean = false;
  showBranchItemModal: boolean = false;
  //#endregion
  //#region Variables
  vendors: VendorInfo[];
  filteredVendors: VendorInfo[];
  vendorPage: number = 1;
  searchVendor: string = "";
  vendorContract: VendorContract;
  selectedVendor: VendorInfo;
  selectedRowIndex: number = -1;
  vendorBranch: Array<VendorBranchInfo & { isChecked: boolean }>;
  vendorBranchPage: number = 1;
  selectedBranches: VendorBranchInfo[] = [];
  namingRef: StaticRef[];
  itemResultCount: number = 0;
  itemList: Array<ItemInfo & { isChecked: boolean }>;
  itemsPage: number = 1;
  searchItemTerm: string = "";
  selectedItems: ItemInfo[] = [];
  allItemSelected: boolean = false;
  notSelectedItems: ItemInfo[] = [];
  categories: Category[] = [];
  categoriesWithoutRoot: Category[] = [];
  categoryPage: number = 1;
  breadcrumbs: Category[] = [];
  currentParentCatCode: number = null;
  selectedCategory: Category[];
  filteredCategories: Category[];
  searchCategoryTerm: string = "";
  selectedLeafCat: Category[];
  selectedVendorBranch: VendorBranchInfo;
  branchItems: VendorBranchItem[] = [];
  branchItemsPage: number = 1;
  branchItemsCount: number = 0;
  branchItemsSearchTerm: string = "";
  savedbranchItemsSearchTerm: string = "";
  selectedBranchItem: VendorBranchItem;
  selectedBranchItemCategoryPath: Category[];
  //#endregion

  //#region Forms
  branchItemForm: FormGroup = this.formbuilder.group({
    itemCode: [null],
    itemPrice: [0, Validators.required],
    fundedPrice: [0, Validators.required],
    activeRec: [1],
    uuc: [""],
  });
  //#endregion

  constructor(
    private vendorService: VendorService,
    public pagingService: pagingService,
    private alertService: AlertService,
    private cdref: ChangeDetectorRef,
    private formbuilder: FormBuilder,
    private referencesService: ReferencesService,
    public inputMaskingService: InputMaskingService
  ) {}

  //#region Initialization
  async ngOnInit() {
    this.showLoader = true;
    this.namingRef = await this.referencesService
      .getCategoriesItemsRef()
      .toPromise();
    let cat = await this.vendorService.getCategories();
    this.categoriesWithoutRoot = this.getActiveCategories(cat);
    this.categories = [
      {
        catCode: 0,
        catName: "جميع " + this.getNamingRefValue("3"),
        leafCat: null,
        username: null,
        updateStamp: null,
        itemsCount: 0,
        uuc: null,
        activeRec: 1,
        subCategories: this.categoriesWithoutRoot,
      },
    ];
    this.filteredCategories = this.categories;
    await this.vendorService.getActiveVendors().then((res) => {
      this.vendors = res;
      this.filteredVendors = res;
      this.showVendors = true;
    });
    this.showLoader = false;
  }
  ngAfterContentChecked(): void {
    this.cdref.detectChanges();
  }
  getNamingRefValue(code: string): string {
    const ref = this.namingRef?.find((ref) => ref.ref_code === code);
    return ref?.ref_desc ?? "";
  }
  //#endregion

  //#region Vendors
  search($event: Event) {
    const input = $event.target as HTMLInputElement;
    this.searchVendor = input.value;
    this.vendorPage = 1;

    this.filteredVendors = this.vendors.filter(
      (v) =>
        this.searchVendor == "" ||
        v.vendor_name.toLowerCase().match(this.searchVendor.toLowerCase())
    );
  }
  async openVendor(vendor: VendorInfo) {
    this.showLoader = true;
    this.selectedVendor = vendor;
    this.vendorService
      .getActiveVendorContracts(vendor.vendor_code)
      .then(async (res) => {
        this.vendorContract = res;
        await this.vendorService
          .getActiveVendorContractBranches(vendor.vendor_code)
          .then(async (res) => {
            this.vendorBranch = res.map((x) => ({
              ...x,
              isChecked: false,
            }));
            this.showCategories = true;
            this.showVendors = false;
            this.showLoader = false;
          });
      })
      .catch((err) => {
        console.error(err);
        this.showLoader = false;
      });
  }
  changeVendorPage(newPage: number): void {
    this.vendorPage = newPage;
  }
  //#endregion

  //#region Items and Branches
  changeBranchPage(newPage: number): void {
    this.vendorBranchPage = newPage;
  }
  changePaginationPage = async (newPage: number) => {
    this.itemsPage = newPage;
    await this.getItems();
  };
  async getItems() {
    this.showLoader = true;
    let leafCatString = this.selectedLeafCat
      .map((c) => c.catCode.toString())
      .join(",");
    await this.vendorService
      .getActiveItems(this.searchItemTerm, this.itemsPage, leafCatString)
      .toPromise()
      .then((res) => {
        this.showItems = true;
        this.itemResultCount = res["count"];
        this.itemList = res["result"].map((x) => ({
          ...x,
          isChecked: this.getCheckStatus(x),
        }));
        this.showLoader = false;
      });
  }
  getCheckStatus(item: ItemInfo): boolean {
    if (this.allItemSelected) {
      if (this.notSelectedItems.find((x) => x.itemCode === item.itemCode))
        return false;
      else return true;
    } else {
      if (this.selectedItems.find((x) => x.itemCode === item.itemCode))
        return true;
      else return false;
    }
  }
  async assignItems() {
    if (await this.alertService.SaveAlert("هل تريد الحفظ؟")) {
      if (this.selectedBranches.length === 0) {
        this.alertService.showAlertError("يجب اختيار فروع", false);
        return;
      }
      if (this.selectedItems.length === 0 && !this.allItemSelected) {
        this.alertService.showAlertError(
          "يجب اختيار " + this.getNamingRefValue("3"),
          false
        );
        return;
      }
      this.showLoader = true;
      let request: AssignItemsRequest = {
        vendorCode: this.selectedVendor.vendor_code,
        categories: this.selectedLeafCat
          .map((c) => c.catCode.toString())
          .join(","),
        vendorBranches: this.selectedBranches,
        selectedItems: this.selectedItems,
        notSelectedItems: this.notSelectedItems,
        allItemsSelected: this.allItemSelected === true ? 1 : 0,
      };
      await this.vendorService
        .assignItemsToBranches(request)
        .then(async () => {
          await this.alertService.showAlertConfirm(
            "تم تعيين " + this.getNamingRefValue("3") + " للفروع ",
            false
          );
        })
        .catch(async (err) => {
          console.log(err.error);
          await this.alertService.showAlertError(err.error, false);
          return;
        })
        .finally(() => {
          this.showLoader = false;
        });
    }
  }
  //#endregion

  //#region Category
  changeCategoryPage(newPage: number): void {
    this.categoryPage = newPage;
  }
  getActiveCategories(categories: Category[]): Category[] {
    return categories
      .filter((cat) => cat.activeRec === 1)
      .map((cat) => ({
        ...cat,
        subCategories: this.getActiveCategories(cat.subCategories),
      }));
  }
  getLeafCategoriesUnder(catCode: number): Category[] {
    const findCategoryByCode = (
      categories: Category[],
      code: number
    ): Category | undefined => {
      for (const cat of categories) {
        if (cat.catCode === code) return cat;
        const found = findCategoryByCode(cat.subCategories, code);
        if (found) return found;
      }
      return undefined;
    };

    const collectLeafCategories = (category: Category): Category[] => {
      if (category.leafCat) return [category];
      let leaves: Category[] = [];
      for (const sub of category.subCategories) {
        leaves = leaves.concat(collectLeafCategories(sub));
      }
      return leaves;
    };

    const startCategory = findCategoryByCode(this.categories, catCode);
    if (!startCategory) return [];
    return collectLeafCategories(startCategory);
  }
  async navigateCategory(cat: Category) {
    const element = this.categoryContainer.nativeElement;
    element.classList.add("swipe-right");
    await new Promise((resolve) => {
      element.addEventListener(
        "animationend",
        () => {
          resolve(true);
        },
        { once: true }
      );
    });

    this.showLoader = true;
    this.currentParentCatCode = cat.catCode;
    if (!this.breadcrumbs.includes(cat)) {
      this.breadcrumbs.push(cat);
    } else {
      if (this.breadcrumbs.indexOf(cat) + 1 < this.breadcrumbs.length) {
        this.breadcrumbs = this.breadcrumbs.slice(
          0,
          this.breadcrumbs.indexOf(cat) + 1
        );
      }
    }
    this.selectedCategory = cat.subCategories;
    this.filteredCategories = cat.subCategories;
    this.searchCategoryTerm = "";
    this.categoryPage = 1;
    this.showLoader = false;
    element.classList.remove("swipe-right");
  }
  async backCategoryLevel() {
    this.showLoader = true;
    this.breadcrumbs.pop();
    if (this.breadcrumbs.length > 0) {
      this.navigateCategory(this.breadcrumbs[this.breadcrumbs.length - 1]);
    } else {
      const element = this.categoryContainer.nativeElement;
      element.classList.add("swipe-right");
      await new Promise((resolve) => {
        element.addEventListener(
          "animationend",
          () => {
            resolve(true);
          },
          { once: true }
        );
      });
      this.selectedCategory = this.categories;
      this.filteredCategories = this.categories;
      this.currentParentCatCode = null;
      this.categoryPage = 1;
      this.searchCategoryTerm = "";
      element.classList.remove("swipe-right");
    }
    this.showLoader = false;
  }
  async returnToHome() {
    if (this.selectedCategory === this.categories) return;

    const element = this.categoryContainer.nativeElement;
    element.classList.add("swipe-right");
    await new Promise((resolve) => {
      element.addEventListener(
        "animationend",
        () => {
          resolve(true);
        },
        { once: true }
      );
    });
    this.showLoader = true;
    this.breadcrumbs = [];
    this.selectedCategory = this.categories;
    this.filteredCategories = this.categories;
    this.currentParentCatCode = null;
    this.categoryPage = 1;
    this.searchCategoryTerm = "";
    this.showLoader = false;
    element.classList.remove("swipe-right");
  }
  async getCategoryItems(cat: Category) {
    this.showLoader = true;
    this.selectedLeafCat = this.getLeafCategoriesUnder(cat.catCode);
    await this.getItems().then(() => {
      this.showItems = true;
      this.showCategories = false;
      this.showLoader = false;
    });
  }
  backToVendors() {
    if (this.showItems) {
      this.itemsPage = 1;
      this.showItems = false;
      this.showCategories = true;
    } else if (this.showCategories) {
      this.vendorBranch = null;
      this.vendorContract = null;
      this.showCategories = false;
      this.showVendors = true;
      this.itemList = [];
      this.selectedItems = [];
      this.notSelectedItems = [];
      this.itemResultCount = 0;
      this.searchItemTerm = "";
      this.allItemSelected = false;
    }
  }
  getCategoryPathArray(
    categories: Category[],
    targetCatCode: number
  ): Category[] | null {
    for (const category of categories) {
      if (category.catCode === targetCatCode) {
        return [category];
      }

      if (category.subCategories?.length) {
        const subPath = this.getCategoryPathArray(
          category.subCategories,
          targetCatCode
        );
        if (subPath) {
          return [category, ...subPath];
        }
      }
    }

    return null;
  }
  //#endregion

  //region Checbox Branches
  set isAllBranchesSelected(value: boolean) {
    this.vendorBranch.forEach((br) => (br.isChecked = value));
  }
  onBranchesCheckboxMasterChange(event: any) {
    const isChecked = event.target.checked;
    this.vendorBranch.forEach((br) => (br.isChecked = isChecked));
    this.updateSelectedBranchesForAll(isChecked);
  }
  updateSelectedBranchesForAll(isChecked: boolean) {
    this.selectedBranches = [];
    if (isChecked) {
      this.vendorBranch.forEach((br) => {
        this.selectedBranches.push(br);
      });
    }
  }
  onBranchCheckboxChange(event: any, br: any, index: any) {
    const selectedApp =
      this.vendorBranch[
        index + this.pagingService.pageSize * (this.vendorBranchPage - 1)
      ];

    selectedApp.isChecked = event.target.checked;
    this.updateSelectedBranch(br, event.target.checked);
    this.updateBranchMasterCheckbox();
    if (this.vendorBranch.length !== this.selectedBranches.length) {
      if (this.selectedBranches.length === 0) {
        this.ionCheckBoxBranches.indeterminate = false;
      } else {
        this.ionCheckBoxBranches.indeterminate = true;
      }
    } else if (this.vendorBranch.length === this.selectedBranches.length) {
      this.ionCheckBoxBranches.indeterminate = false;
      this.ionCheckBoxBranches.checked = true;
      this.isAllBranchesSelected = true;
    }
  }
  updateSelectedBranch(br: any, isChecked: boolean) {
    const index = this.selectedBranches!.indexOf(br);
    if (isChecked && index === -1) {
      this.selectedBranches.push(br);
    } else if (!isChecked && index > -1) {
      this.selectedBranches.splice(index, 1);
    }
  }
  updateBranchMasterCheckbox() {
    const allSelected = this.vendorBranch.every((app) => app.isChecked);
    const someSelected = this.vendorBranch.some((app) => app.isChecked);

    if (allSelected) {
      this.isAllBranchesSelected = true;
    } else if (!someSelected) {
      this.ionCheckBoxBranches.checked = false;
      this.ionCheckBoxBranches.indeterminate = false;
      this.isAllBranchesSelected = false;
    }
  }
  //endregion

  //region Checbox Items
  onItemsCheckboxMasterChange(event: any) {
    const isChecked = event.target.checked;
    if (isChecked) {
      this.allItemSelected = true;
      this.ionCheckBoxItems.checked = true;
      this.ionCheckBoxItems.indeterminate = false;
      this.itemList.forEach((x) => (x.isChecked = true));
      this.selectedItems = [];
      this.notSelectedItems = [];
    } else {
      this.ionCheckBoxItems.checked = false;
      this.ionCheckBoxItems.indeterminate = false;
      this.allItemSelected = false;
      this.itemList.forEach((x) => (x.isChecked = false));
      this.selectedItems = [];
      this.notSelectedItems = [];
    }
  }
  onItemCheckboxChange(event: any, br: any) {
    const selectedApp = br;
    selectedApp.isChecked = event;
    this.updateSelectedItem(selectedApp);
    if (this.allItemSelected) {
      if (this.notSelectedItems.length === this.itemResultCount) {
        this.ionCheckBoxItems.checked = false;
      } else {
        if (this.notSelectedItems.length > 0) {
          this.ionCheckBoxItems.indeterminate = true;
        } else {
          this.ionCheckBoxItems.indeterminate = false;
        }
      }
    } else {
      if (this.selectedItems.length === this.itemResultCount) {
        this.ionCheckBoxItems.checked;
      } else {
        if (this.selectedItems.length > 0) {
          this.ionCheckBoxItems.indeterminate = true;
        } else {
          this.ionCheckBoxItems.indeterminate = false;
        }
      }
    }
  }
  updateSelectedItem(br: any) {
    if (this.allItemSelected) {
      const index = this.notSelectedItems.indexOf(br);
      if (!br.isChecked && index === -1) {
        this.notSelectedItems.push(br);
      } else if (br.isChecked && index > -1) {
        this.notSelectedItems.splice(index, 1);
      }
    } else {
      const index = this.selectedItems.indexOf(br);
      if (br.isChecked && index === -1) {
        this.selectedItems.push(br);
      } else if (!br.isChecked && index > -1) {
        this.selectedItems.splice(index, 1);
      }
    }

    console.log("this.selectedItems", this.selectedItems);
    console.log("this.notSelectedItems", this.notSelectedItems);
  }
  //endregion

  //#region Branch Items
  async openBranch(branch: VendorBranchInfo) {
    this.selectedVendorBranch = branch;
    this.showBranchItems = true;
    this.showItems = false;
    this.showCategories = false;
    this.selectedBranches = [];
    this.selectedItems = [];
    this.notSelectedItems = [];
    this.allItemSelected = false;
    this.vendorBranch.forEach((x) => (x.isChecked = false));
    await this.getBranchItems();
  }
  async searchBranchItems() {
    this.showLoader = true;
    this.branchItemsSearchTerm = this.searchBranchItemInput.value.toString();
    if (this.savedbranchItemsSearchTerm != this.branchItemsSearchTerm)
      this.branchItemsPage = 1;
    await this.vendorService
      .getBranchItems(
        this.branchItemsSearchTerm,
        this.branchItemsPage,
        this.selectedVendorBranch.vendorCode,
        this.vendorContract[0].vendContractCode,
        this.selectedVendorBranch.vendorBrCode
      )
      .toPromise()
      .then((res) => {
        this.savedbranchItemsSearchTerm = this.branchItemsSearchTerm;
        this.branchItemsCount = res.count;
        this.branchItems = res["result"];
        this.showLoader = false;
      });
  }
  async getBranchItems() {
    this.showLoader = true;
    this.vendorService
      .getBranchItems(
        this.branchItemsSearchTerm,
        this.branchItemsPage,
        this.selectedVendorBranch.vendorCode,
        this.vendorContract[0].vendContractCode,
        this.selectedVendorBranch.vendorBrCode
      )
      .toPromise()
      .then((res) => {
        this.branchItemsCount = res.count;
        this.branchItems = res["result"];
        this.showBranchItems = true;
        this.showItems = false;
        this.showCategories = false;
      })
      .catch(async (err) => {
        await this.alertService.showAlertError(err.error, false);
      })
      .finally(() => {
        this.showLoader = false;
      });
  }
  backToItems() {
    this.showLoader = true;
    this.showBranchItems = false;
    this.branchItems = [];
    this.branchItemsCount = 0;
    this.branchItemsPage = 1;
    this.branchItemsSearchTerm = "";
    this.showItems = false;
    this.showCategories = true;
    this.showLoader = false;
  }
  async changeBranchItemPage(newPage: number) {
    this.branchItemsPage = newPage;
    await this.getBranchItems();
  }
  openBranchItemModal(item: VendorBranchItem) {
    this.selectedBranchItem = item;
    this.selectedBranchItemCategoryPath = this.getCategoryPathArray(
      this.categoriesWithoutRoot,
      item.catCode
    ) as Category[];
    this.branchItemForm.patchValue({
      itemCode: item.itemCode,
      itemPrice: item.itemPrice,
      fundedPrice: item.fundedPrice,
      activeRec: item.activeRec === 1,
      uuc: item.uuc,
    });
    this.showBranchItemModal = true;
  }
  closeBranchItemModal() {
    this.showBranchItemModal = false;
    this.branchItemForm.reset();
  }
  async editBranchItem() {
    if (await this.alertService.SaveAlert("هل تريد الحفظ؟")) {
      if (this.branchItemForm.valid) {
        this.showLoader = true;
        let request: EditBranchItem = {
          vendorCode: this.selectedBranchItem.vendorCode,
          vendContractCode: this.selectedBranchItem.vendContractCode,
          vendorBrCode: this.selectedBranchItem.vendorBrCode,
          uuc: this.branchItemForm.value.uuc,
          itemCode: this.branchItemForm.value.itemCode,
          itemPrice: this.branchItemForm.value.itemPrice,
          fundedPrice: this.branchItemForm.value.fundedPrice,
          activeRec: this.branchItemForm.value.activeRec === true ? 1 : 0,
        };
        this.vendorService
          .editBranchItem(request)
          .then(async () => {
            await this.alertService.showAlertConfirm(
              "تم حفظ ال" + this.getNamingRefValue("4") + " بنجاح",
              false
            );
            this.searchBranchItems().then(() => {
              this.closeBranchItemModal();
              this.showLoader = false;
            });
          })
          .catch(async (err) => {
            await this.alertService.showAlertError(err.error, false);
            this.showLoader = false;
          });
      }
    }
  }
  async deleteBranchItem(item: VendorBranchItem) {
    if (
      await this.alertService.SaveAlert(
        "هل تريد حذف هذا ال" + this.getNamingRefValue("4") + " من هذا الفرع؟"
      )
    ) {
      this.showLoader = true;
      let request: DeleteBranchItem = {
        vendorCode: item.vendorCode,
        vendContractCode: item.vendContractCode,
        vendorBrCode: item.vendorBrCode,
        uuc: item.uuc,
        itemCode: item.itemCode,
      };
      this.vendorService
        .deleteBranchItem(request)
        .then(async () => {
          await this.alertService.showAlertConfirm(
            "تم حذف ال" + this.getNamingRefValue("4") + " بنجاح",
            false
          );
          this.searchBranchItems();
        })
        .catch(async (err) => {
          await this.alertService.showAlertError(err.error, false);
          this.showLoader = false;
        });
    }
  }
  //#endregion
}
